import{_ as l,c as t,a as e,o as r}from"./app-CEcM0piI.js";const o={};function s(n,i){return r(),t("div",null,i[0]||(i[0]=[e('<p><strong>⌚️投递时间：5.12</strong></p><p><strong>👋一面（技术面）：5.26</strong></p><p><strong>🤏二面（技术面）：5.27</strong></p><p><strong>✌️三面（hr面）：5.28</strong></p><p><strong>无oc，hr面挂</strong></p><p>很多都记不太清了只挑了些印象深刻的发出来了</p><p><strong>一面（5.26）：</strong></p><p>面试官说话特别好特别健谈，鼠鼠一个社恐都被他带的说了很多</p><p>主要是看项目，然后根据项目问了些项目相关的知识点以及情景题：</p><p>（可能因为我的技术栈主要是vue，而他们团队用的react我没学所以问的八股少点？）</p><ol><li>看了下项目中ts的使用</li><li>axios的封装</li><li>根据axios的封装问了点节流</li><li>看了下echarts做的图表</li><li>问请求的数据如何处理的（我做了点缓存就说了说），其他的问题记不太清了</li><li>简历中有写了解node是自学的吗</li><li>为什么node只学一部分</li><li>使用java都做过什么项目</li><li>反问</li></ol><p>大约聊了半个多小时。</p><p><strong>二面（5.27）：</strong></p><p>二面也是看项目，根据项目问些情景题和知识点：</p><ol><li>路由跳转时如何保存用户当前浏览到的位置</li><li>图片加载完成的事件（记不太清了，大概就是这个知识点）</li><li>事件循环</li><li>浏览器渲染原理</li><li>重排和重绘</li><li>web worker线程</li><li>promise</li><li>async/await原理</li><li>pnpm_lock</li><li>幽灵依赖</li><li>css动画</li><li>canvans</li><li>树形组件查找某一节点算法</li><li>反问</li></ol><p><strong>三面（5.28）：</strong></p><ol><li>工作都考虑哪些地方</li><li>为什么考虑这些地方</li><li>简历中有写c++，python，后端游戏这些技术是自学的吗</li><li>讲讲自己的项目（不涉及技术，说说项目怎么弄的吗，是老师的还是自己网上找的）</li><li>简历上有一个项目持续时间是从上一年到至今的，为什么还没截至（这个是本人开发的vscode插件，因此一直在维护）</li><li>开发这个插件的契机</li><li>用三个词来形容自己</li><li>对众安的了解</li><li>为什么选择我们</li><li>前端团队三个方向：大前端、业务/架构、动画。选择哪个方向</li><li>反问</li></ol><p>6.03问了下hr，没过，hr面挂了，说是我留在本地的意愿不高。</p><p>整个流程挺快的，其实三面后第二天就该问的，之前每次都是当前面完下午出结果</p><p>总结：是鼠鼠当前为止面试体验最好的一次面试</p><p>作者：呆虫仙尊<br> 链接：<a href="https://www.nowcoder.com/discuss/760591238562131968?sourceSSR=users" target="_blank" rel="noopener noreferrer">https://www.nowcoder.com/discuss/760591238562131968?sourceSSR=users</a><br> 来源：牛客网</p>',21)]))}const a=l(o,[["render",s]]),c=JSON.parse('{"path":"/article/20250615/","title":"众安前端实习面试time line","lang":"zh-CN","frontmatter":{"title":"众安前端实习面试time line","createTime":"2025/06/15 17:18","tags":["面经","前端"],"permalink":"/article/20250615/"},"readingTime":{"minutes":2.29,"words":688},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"面试/众安前端实习面试time line.md","headers":[],"categoryList":[{"id":"1573c7","sort":10000,"name":"面试"}]}');export{a as comp,c as data};
